#include <stdio.h>
int main() {
    int T, n, a[100005], b[100005], max_len, len, i, j;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        max_len = 0;
        for (i = 0; i < n; i++) {
            len = 0;
            b[len++] = a[i];
            for (j = i + 1; j < n; j++) {
                if (a[j] >= b[len - 1]) {
                    b[len++] = a[j];
                }
            }
            if (len > max_len) {
                max_len = len;
            }
        }
        printf("%d\n", max_len);
    }
    return 0;
}

