        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextInt();
            }
            int max_len = 0;
            for (int i = 0; i < n; i++) {
                int len = 0;
                int[] b = new int[n];
                b[len++] = a[i];
                for (int j = i + 1; j < n; j++) {
                    if (a[j] >= b[len - 1]) {
                        b[len++] = a[j];
                    }
                }
                if (len > max_len) {
                    max_len = len;
                }
            }
            System.out.println(max_len);
        }
